export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  watchQuery: true,
  async asyncData({ $get, query }) {
    const type = query.type || "1";
    let { data:{list, count }} = await $get("goods_comment/getOrderGoods", {
      params: { type: type,  page_size: 10 },
    });
    return {
      commentList: { list, count },
      type,
    };
  },
  layout: "user_lauout",
  components: {},
  data() {
    return {
      evaluate: [
        {
          type: "1",
          list: [],
          name: "待评价",
          count: 0,
          page: 1,
        },
        {
          type: "2",
          list: [],
          name: "已评价",
          count: 0,
          page: 1,
        },
      ],
    };
  },
  methods: {
     handleClick() {
      this.getEvaluateList();
    },
    async getEvaluateList() {
      const { type, evaluate } = this;
      const item = evaluate.find((item) => item.type == type);
      const {
        data: { list, count },
        code,
      } = await this.$get("goods_comment/getOrderGoods", {
        params: {
          page_size: 10,
          page_no: item.page,
          type,
        },
      });
      if (code == 1) {
        this.commentList = { list, count };
      }
    },
    changePage(val) {
      this.evaluate.some((item) => {
        if (item.type == this.type) {
          item.page = val;
        }
      });
      this.getEvaluateList();
    },
  },
  watch: {
    commentList: {
      immediate: true,
      handler(val) {
        this.evaluate.some((item) => {
          if (item.type == this.type) {
            Object.assign(item, val);
            console.log(item);
            return true;
          }
        });
      },
    },
  }
};
